script.text:

          DO $$
            BEGIN
              IF EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'historyupdatequeueitemsupsert') THEN
                DROP FUNCTION &&HistoryUpdateQueueItemsUpsert&&(tvp json);
              END IF;

              IF EXISTS (SELECT 1 FROM pg_type WHERE typname = 'historyobjectobservertabletype') THEN
                DROP TYPE &&HistoryObjectObserverTableType&&;
              END IF;

              CREATE TYPE &&HistoryObjectObserverTableType&& AS (
	              &&Parent&& VARCHAR(70),
                &&Child&& VARCHAR(70));
            END$$;

DO $$ BEGIN IF EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'historyobjectsupsert') THEN DROP FUNCTION &&HistoryObjectsUpsert&&(tableName text, tvp json); END IF;
IF EXISTS (SELECT 1 FROM pg_type WHERE typname = 'historyobjecttabletype') THEN DROP TYPE &&HistoryObjectTableType&&; END IF;
CREATE TYPE &&HistoryObjectTableType&& AS ( &&Id&& BIGINT, &&Uid&& UUID, &&Object&& VARCHAR(70), &&Model&& TEXT, &&ActionDate&& TIMESTAMP, &&ActionTypeUid&& UUID, &&CreationAuthor&& BIGINT, &&EventArgsUid&& UUID, &&SessionUid&& UUID, &&UnitOfWorkUid&& UUID, &&IsRelatedEvent&& BOOLEAN); END$$;


          DO $$
            BEGIN
              IF EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'historyupdatequeueitemsupsert') THEN
                DROP FUNCTION &&HistoryUpdateQueueItemsUpsert&&(tvp json);
              END IF;

              IF EXISTS (SELECT 1 FROM pg_type WHERE typname = 'historyupdatequeueitemtabletype') THEN
                DROP TYPE &&HistoryUpdateQueueItemTableType&&;
              END IF;

              CREATE TYPE &&HistoryUpdateQueueItemTableType&& AS (
	              &&Id&& BIGINT,
                &&ObjectId&& BIGINT,
	              &&ObjectTypeUid&& UUID,
                &&DeleteRelated&& BOOLEAN,
	              &&CreationDate&& TIMESTAMP,
                &&NextUpdateDate&& TIMESTAMP);
            END$$;

procedure.text:

          CREATE OR REPLACE FUNCTION &&UpdateCachedHistoryObjects&&(tableName text, oldObject text, newObject text) RETURNS void
          AS $$
          BEGIN
	          EXECUTE 'UPDATE ' || tableName || ' SET &&Object&& = ''' || newObject || ''' WHERE &&Object&& = ''' || oldObject || ''';';
	          UPDATE &&HistoryObjectObserver&& SET &&Parent&& = newObject WHERE &&Parent&& = oldObject;
            UPDATE &&HistoryObjectObserver&& SET &&Child&& = newObject WHERE &&Child&& = oldObject;
          END
          $$
          LANGUAGE plpgsql;
